import { NextResponse } from "next/server";
import vision from "@google-cloud/vision";
import { Storage } from "@google-cloud/storage";
import multer from "multer";
import fs from "fs-extra";
import path from "path";
import { promisify } from "util";

// Configure Google Cloud credentials (Set in .env file)
process.env.GOOGLE_APPLICATION_CREDENTIALS = path.join(
  process.cwd(),
  "practical-range-449407-g0-985a4ca620f8.json"
);

// Google Cloud Clients
const visionClient = new vision.ImageAnnotatorClient();
const storage = new Storage();
const upload = multer({ dest: "public/uploads/" });

const uploadMiddleware = promisify(upload.single("file"));

// Function to upload PDF to Google Cloud Storage
async function uploadToGCS(
  localFilePath: string,
  bucketName: string,
  destFileName: string
) {
  await storage.bucket(bucketName).upload(localFilePath, {
    destination: destFileName,
    public: false,
  });
  return `gs://${bucketName}/${destFileName}`;
}

// Function to extract text from PDF
async function extractTextFromPDF(gcsSourceUri: string) {
  const request = {
    requests: [
      {
        inputConfig: {
          gcsSource: { uri: gcsSourceUri },
          mimeType: "application/pdf",
        },
        features: [{ type: "DOCUMENT_TEXT_DETECTION" }],
      },
    ],
  };

  const [operation] = await visionClient.asyncBatchAnnotateFiles(request);
  const [filesResponse] = await operation.promise();
  return filesResponse.responses[0].fullTextAnnotation.text;
}

// Function to check if the document is a marksheet
function isMarksheet(text: string) {
  const keywords = ["percentage", "marks", "total", "subject", "grade", "CGPA"];
  return keywords.some((keyword) => text.toLowerCase().includes(keyword));
}

// API Endpoint
export async function POST(req: Request) {
  try {
    // Parse FormData
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    // Save uploaded file locally
    const localFilePath = path.join("public/uploads", file.name);
    const fileBuffer = Buffer.from(await file.arrayBuffer());
    await fs.writeFile(localFilePath, fileBuffer);

    const bucketName = "your-bucket-name"; // Replace with your GCS bucket
    const destFileName = `uploads/${file.name}`;

    // Upload file to Google Cloud Storage
    const gcsUri = await uploadToGCS(localFilePath, bucketName, destFileName);

    // Extract text from PDF
    const extractedText = await extractTextFromPDF(gcsUri);

    // Check if it's a marksheet
    const result = isMarksheet(extractedText)
      ? "✅ This document is a marksheet."
      : "❌ This document is NOT a marksheet.";

    // Cleanup local file
    await fs.remove(localFilePath);

    return NextResponse.json({ text: extractedText, isMarksheet: result });
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { error: "Failed to process document." },
      { status: 500 }
    );
  }
}
